function []=showTextPage(w,textFile,fontSize,startLine,lineDist)% ShowTextPage(w,textFile,[headLine],[fontSize],[startLine],[lineDist],[BACKCOL])% displays text from texFile on screen w% with string headLine (default '') in bold font% with fontSize (default 12),% starting at Line starLine (default 1)% and with line distance lineDist (default 1.3)% BACKCOL defaults to const.bgColor or if not available to [127 127 127] (and 0 for colorDepth 8)%% if the file texFile doesn't exist, the function displays the string in textFile% the tag \n is available with files and strings% 2004 Eike Richter,% 2006 adopted to PsychToolBox 3 (Mac OSX) by Martin Rolfsglobal visual scr;if scr.colDept==8    col = 127;else    col = [127 127 127 255];endBACKCOL = visual.bgColor;col     = visual.fgColor/2;headLine = '';textWidth = scr.xres / 18;maxLine   = floor(scr.yres / lineDist / fontSize);if startLine >= maxLine    error('startLine is too large for chosen fontSize!');endfinish = 0;while ~finish    rubber([]);        textPage = w;    Screen(textPage,'TextFont','Courier');    Screen(textPage,'TextSize',18);        text = {};    if exist(textFile,'file')        fid = fopen(textFile,'r');        while ~feof(fid)            text = [text {[fscanf(fid,'%s',1) ' ']}];        end        fclose(fid);    else        idx = [0 findstr(textFile,' ')];        for i = 1:(length(idx)-1)            text = [text {textFile((idx(i)+1):idx(i+1))}];        end        text = [text {textFile((idx(end)+1):end)}]; %#ok<AGROW>    end        k 	      = 1;        string = [];    line   = startLine;    Screen(textPage,'FillRect',BACKCOL);    Screen(textPage,'TextStyle',1);        Screen(textPage,'DrawText',headLine,0.1 * scr.xres,lineDist * fontSize,col);    Screen('TextStyle',textPage,0);        for i=k:length(text)        tmp = char(text(i));        if length([string tmp]) < textWidth && ~strcmp(tmp,'\n ')            string = [string tmp]; %#ok<AGROW>        else            Screen('DrawText',textPage,string,0.1 * scr.xres,lineDist * line * fontSize,col);            if ~strcmp(tmp,'\n ')                string = tmp;            else                string = '';            end            line = line + 1;        end        if line == (maxLine - 1)            break;        end    end    k = i; %#ok<NASGU>        Screen('DrawText',textPage,string,0.1 * scr.xres,lineDist * line * fontSize,col);    flushkeys;    Screen('DrawText',textPage,'Press space bar to continue.',0.1 * scr.xres,lineDist * line * fontSize*2 ,col);        Screen(scr.main,'Flip');        if nargin == 8;        try            feval(evalFn);        catch        end    end        [keyPressed] = WaitKeyPress([44 30 31]);        switch keyPressed        case 1  % space            finish = 1;        case 2  % 1            finish = 0;            showEvent(1);        case 3  % 2            finish = 0;            showEvent(2);        otherwise    endendWaitSecs(0.2);rubber([]);Screen(scr.main,'Flip');